  document:{kind:'quote',view:'all',search:'',client:'',owner:'',opportunity:'',dateFrom:'',dateTo:'',min:'',max:'',sort:'created_at',direction:'desc',page:1,size:20,selected:new Set(),columnsOpen:false},
  dashboard:{period:storage.get('piloz_dashboard_period','month'),customFrom:'',customTo:'',configOpen:false},
