 const defaultColumns={quote:['select','number','client','subject','issue_date','validity_date','ht','vat','ttc','cost','margin','status','opportunity','owner','last_reminder','created_at','actions'],invoice:['select','number','type','client','issue_date','due_date','ht','vat','ttc','paid','remaining','cost','margin','status','last_reminder','owner','actions']};
 const columnLabels={select:'',number:'Numéro',type:'Type',client:'Client',subject:'Objet',issue_date:'Émission',validity_date:'Validité',due_date:'Échéance',ht:'HT',vat:'TVA',ttc:'TTC',cost:'Coût d’achat',margin:'Marge',status:'Statut',opportunity:'Opportunité',owner:'Responsable',last_reminder:'Dernière relance',created_at:'Création',paid:'Encaissé',remaining:'Reste à payer',actions:'Actions'};
 const statusLabels={draft:'Brouillon',to_send:'À envoyer',sent:'Envoyé',viewed:'Consulté',accepted:'Accepté',rejected:'Refusé',expired:'Expiré',invoiced:'Facturé',archived:'Archivé',validated:'Envoyée',partially_paid:'Partiellement payée',paid:'Payée',overdue:'En retard',cancelled:'Annulée',confirmed:'Confirmée',partial:'Partiel',pending:'En attente',completed:'Terminée'};
 const typeLabels={quote:'Devis',invoice:'Facture',deposit_invoice:'Facture d’acompte',balance_invoice:'Facture de solde',credit_note:'Avoir',proforma_invoice:'Pro forma',recurring_invoice:'Facture récurrente',purchase_invoice:'Facture fournisseur'};
 const widgetCatalog={
  revenue:{title:'Chiffre d’affaires HT',width:1},previous:{title:'CA période N-1',width:1},evolution:{title:'Évolution N / N-1',width:1},revenueTtc:{title:'Chiffre d’affaires TTC',width:1},collected:{title:'Montant encaissé',width:1},outstanding:{title:'Reste à encaisser',width:1},overdue:{title:'Montant en retard',width:1},quotesPending:{title:'Devis en attente',width:1},conversion:{title:'Taux de transformation',width:1},margin:{title:'Marge brute',width:1},pipeline:{title:'Valeur du pipeline',width:1},todayReminders:{title:'Relances du jour',width:1},monthly:{title:'Évolution mensuelle du CA',width:2},topClients:{title:'Top clients',width:2},topItems:{title:'Top articles',width:2},recent:{title:'Activité récente',width:2},stockAlerts:{title:'Stock sous seuil',width:2}
 };
 const defaultWidgets=['revenue','previous','evolution','collected','outstanding','overdue','quotesPending','conversion','margin','pipeline','todayReminders','monthly','topClients','recent','stockAlerts'];

 function activeArea(path){if(path==='dashboard')return'dashboard';if(path==='reports')return'reports';if(path.startsWith('crm/')||['pipeline','relances'].includes(path))return'crm';if(path.startsWith('sales/'))return'sales';if(path.startsWith('purchases/'))return'purchases';if(path.startsWith('stock/'))return'stock';if(path.startsWith('settings')||path==='templates')return'settings';return'dashboard';}
 function counts(state){const docs=state.data.documents||[],reminders=state.data.reminders||[],today=iso(new Date());return{quotes:docs.filter(x=>x.document_type==='quote'&&!['archived','invoiced'].includes(x.status)).length,invoices:docs.filter(x=>['invoice','deposit_invoice','balance_invoice'].includes(x.document_type)&&!['paid','cancelled','archived'].includes(x.status)).length,reminders:reminders.filter(x=>x.status==='pending'&&String(x.due_at).slice(0,10)<=today).length,opportunities:(state.data.opportunities||[]).filter(x=>!['collected','lost'].includes(x.stage)).length,stock:(state.data.levels||[]).filter(level=>{const item=(state.data.catalog||[]).find(x=>x.id===level.item_id);return item&&Number(level.available_quantity)<Number(item.reorder_point||item.minimum_stock||0);}).length};}
 function navItem(path,label,current,state){const c=counts(state),counter=path==='sales/quotes'?c.quotes:path==='sales/invoices'?c.invoices:path==='crm/opportunities'?c.opportunities:path.includes('reminder')?c.reminders:path==='stock/overview'?c.stock:0;return`<button class="modern-secondary-item ${current===path?'active':''}" onclick="PilozApp.go('${path}')"><span>${esc(label)}</span>${counter?`<span class="count">${counter}</span>`:''}</button>`;}
 function renderNavigation(node,state,current){const area=activeArea(current),primary=[['dashboard','Tableau de bord'],['crm','Suivi commercial'],['sales','Ventes'],['purchases','Achats'],['stock','Stock'],['reports','Rapports'],['settings','Paramètres']];document.getElementById('app')?.classList.toggle('modern-subnav-open',ui.secondaryOpen&&!['dashboard','reports'].includes(area));node.innerHTML=`<div class="modern-nav-shell">${primary.map(([key,label])=>`<button class="modern-primary-item ${area===key?'active':''}" onclick="PilozModern.openArea('${key}')" title="${esc(label)}" aria-label="${esc(label)}" ${area===key?'aria-current="page"':''}>${icons[key]}<span>${esc(label)}</span></button>`).join('')}</div>${!['dashboard','reports'].includes(area)?renderSecondary(area,current,state):''}`;}
 function renderSecondary(area,current,state){const data=nav[area];if(!data||!ui.secondaryOpen)return'';let content='';if(data.groups)content=data.groups.map(([label,items])=>`<div class="modern-secondary-label">${esc(label)}</div>${items.map(item=>navItem(item[0],item[1],current,state)).join('')}`).join('');else content=data.items.map(item=>navItem(item[0],item[1],current,state)).join('');return`<aside class="modern-secondary-panel"><div class="modern-secondary-head"><h2>${esc(data.label)}</h2><button onclick="PilozModern.toggleSecondary()" aria-label="Replier le sous-menu">‹</button></div><div class="modern-secondary-items">${content}</div></aside>`;}
 function openArea(area){if(area==='dashboard'||area==='reports'){ui.secondaryOpen=false;app().go(area);return;}ui.secondaryOpen=true;storage.set('piloz_modern_secondary',true);const target=area==='crm'?'crm/overview':area==='sales'?'sales/overview':area==='purchases'?'purchases/overview':area==='stock'?'stock/overview':'settings/company';app().go(target);}
 function toggleSecondary(){ui.secondaryOpen=!ui.secondaryOpen;storage.set('piloz_modern_secondary',ui.secondaryOpen);app().render();}
 function header(title,description,actions=''){return`<header class="modern-page-header"><div><h1>${esc(title)}</h1><p>${esc(description)}</p></div><div class="actions">${actions}</div></header><div id="modern-live" class="sr-only" aria-live="polite"></div>`;}
 function button(label,handler,kind='btn-o',attrs=''){return`<button class="btn ${kind}" onclick="${handler}" ${attrs}>${esc(label)}</button>`;}
 function kpi(label,value,meta='',tone=''){return`<article class="modern-kpi"><span>${esc(label)}</span><strong class="${tone}">${value}</strong>${meta?`<small>${esc(meta)}</small>`:''}</article>`;}
 function empty(title,text,action=''){return`<div class="modern-empty"><h3>${esc(title)}</h3><p>${esc(text)}</p>${action}</div>`;}
 function notify(message,kind='info'){global.toast?.(message);const node=document.getElementById('modern-live');if(node){node.textContent=message;node.dataset.kind=kind;}}
 function clientName(client){return client?.legal_name||client?.trade_name||[client?.first_name,client?.last_name].filter(Boolean).join(' ')||'—';}
 function statusBadge(value){const key=String(value||'draft'),kind=['paid','accepted','completed','confirmed','received'].includes(key)?'success':['rejected','cancelled','archived','overdue','expired'].includes(key)?'danger':['sent','pending','to_send','partially_paid','partial'].includes(key)?'warning':'info';return`<span class="modern-status ${kind}">${esc(statusLabels[key]||key.replaceAll('_',' '))}</span>`;}
 function clientFor(state,id){return(state.data.clients||[]).find(x=>x.id===id);}
 function opportunityFor(state,id){return(state.data.opportunities||[]).find(x=>x.id===id);}
 function paidFor(state,documentId){return(state.data.payments||[]).filter(x=>x.document_id===documentId&&x.status==='confirmed').reduce((sum,x)=>sum+Number(x.amount),0);}
 function costFor(doc){return Number(doc.total_cost)||0;}

 function periodRange(preset,previous=false){const now=new Date(),start=new Date(now),end=new Date(now);start.setHours(0,0,0,0);end.setHours(0,0,0,0);if(preset==='custom'&&ui.dashboard.customFrom&&ui.dashboard.customTo){const a=new Date(ui.dashboard.customFrom+'T00:00:00'),b=new Date(ui.dashboard.customTo+'T23:59:59'),length=b-a+1;if(previous)return{start:new Date(a-length),end:new Date(a-1)};return{start:a,end:b};}if(preset==='previous_month'){start.setDate(1);start.setMonth(start.getMonth()-1);end.setDate(1);if(previous){start.setMonth(start.getMonth()-1);end.setMonth(end.getMonth()-1);}return{start,end};}if(preset==='quarter'){const quarter=Math.floor(now.getMonth()/3);start.setMonth(quarter*3,1);end.setMonth(quarter*3+3,1);}else if(preset==='year'){start.setMonth(0,1);end.setFullYear(end.getFullYear()+1,0,1);}else if(preset==='previous_year'){start.setFullYear(start.getFullYear()-1,0,1);end.setMonth(0,1);}else{start.setDate(1);end.setMonth(end.getMonth()+1,1);}if(previous){const length=end-start;end=new Date(start);start=new Date(start-length);}return{start,end};}
 function inRange(value,range){if(!value)return false;const dateValue=new Date(String(value).length===10?value+'T12:00:00':value);return dateValue>=range.start&&dateValue<range.end;}
 function invoiceSign(doc){return doc.document_type==='credit_note'?-1:1;}
 function dashboardMetrics(state,range){const docs=state.data.documents||[],current=docs.filter(doc=>['invoice','deposit_invoice','balance_invoice','credit_note'].includes(doc.document_type)&&!['draft','cancelled','archived'].includes(doc.status)&&inRange(doc.issue_date,range)),revenue=current.reduce((sum,doc)=>sum+invoiceSign(doc)*Number(doc.total_excl_tax),0),ttc=current.reduce((sum,doc)=>sum+invoiceSign(doc)*Number(doc.total_incl_tax),0),cost=current.reduce((sum,doc)=>sum+invoiceSign(doc)*costFor(doc),0),payments=(state.data.payments||[]).filter(x=>x.status==='confirmed'&&inRange(x.paid_at,range)).reduce((sum,x)=>sum+Number(x.amount),0),allInvoices=docs.filter(doc=>['invoice','deposit_invoice','balance_invoice'].includes(doc.document_type)&&!['cancelled','archived'].includes(doc.status)),outstanding=allInvoices.reduce((sum,doc)=>sum+Math.max(0,Number(doc.total_incl_tax)-paidFor(state,doc.id)),0),today=iso(new Date()),overdue=allInvoices.filter(doc=>doc.due_date&&doc.due_date<today&&!['paid'].includes(doc.status)).reduce((sum,doc)=>sum+Math.max(0,Number(doc.total_incl_tax)-paidFor(state,doc.id)),0),quotes=docs.filter(doc=>doc.document_type==='quote'&&inRange(doc.issue_date,range)),accepted=quotes.filter(x=>['accepted','invoiced'].includes(x.status)),pending=quotes.filter(x=>['draft','to_send','sent','viewed'].includes(x.status)),opportunities=(state.data.opportunities||[]).filter(x=>!['lost','collected'].includes(x.stage)),pipeline=opportunities.reduce((sum,x)=>sum+Number(x.amount||0)*Number(x.probability||0)/100,0),reminders=(state.data.reminders||[]).filter(x=>x.status==='pending'&&String(x.due_at).slice(0,10)===today);return{revenue,ttc,cost,margin:revenue-cost,payments,outstanding,overdue,quotes,accepted,pending,opportunities,pipeline,reminders};}
 function dashboardWidgetKeys(state){const local=storage.get('piloz_dashboard_widgets',null);if(Array.isArray(local))return local.filter(x=>widgetCatalog[x]);const rows=state.data.widgets||[];return rows.length?rows.slice().sort((a,b)=>a.position-b.position).map(x=>x.widget_key).filter(x=>widgetCatalog[x]):defaultWidgets.slice();}
 function setDashboardPeriod(value){ui.dashboard.period=value;storage.set('piloz_dashboard_period',value);app().render();}
 function setDashboardCustom(field,value){ui.dashboard[field]=value;if(ui.dashboard.customFrom&&ui.dashboard.customTo)app().render();}
 function toggleWidgetConfig(){ui.dashboard.configOpen=!ui.dashboard.configOpen;app().render();}
 async function syncWidgets(state,keys){const existing=state.data.widgets||[];for(const row of existing)await api().remove('dashboard_widgets',row.id);if(keys.length)await api().insert('dashboard_widgets',keys.map((widgetKey,index)=>({company_id:state.companyId,user_id:global.PilozRuntime.session.user_id,widget_key:widgetKey,position:index,width:widgetCatalog[widgetKey].width||1})));}
 async function toggleWidget(key){const state=app().getState(),keys=dashboardWidgetKeys(state),visible=keys.includes(key),next=visible?keys.filter(x=>x!==key):[...keys,key];storage.set('piloz_dashboard_widgets',next);app().render();try{await syncWidgets(state,next);await app().refresh();}catch(error){notify('La disposition reste enregistrée sur cet appareil. '+error.message,'error');}}
 async function moveWidget(key,direction){const state=app().getState(),keys=dashboardWidgetKeys(state),from=keys.indexOf(key),to=from+direction;if(to<0||to>=keys.length)return;[keys[from],keys[to]]=[keys[to],keys[from]];storage.set('piloz_dashboard_widgets',keys);app().render();try{await syncWidgets(state,keys);await app().refresh();}catch(error){notify('La disposition reste enregistrée sur cet appareil. '+error.message,'error');}}
 function widgetFrame(key,content,index,total){const def=widgetCatalog[key];return`<article class="modern-widget w${def.width||1}"><header class="modern-widget-head"><h2>${esc(def.title)}</h2><div class="modern-widget-actions"><button onclick="PilozModern.moveWidget('${key}',-1)" ${index===0?'disabled':''} aria-label="Déplacer à gauche">←</button><button onclick="PilozModern.moveWidget('${key}',1)" ${index===total-1?'disabled':''} aria-label="Déplacer à droite">→</button><button onclick="PilozModern.toggleWidget('${key}')" aria-label="Retirer">×</button></div></header>${content}</article>`;}
 function ranked(rows){const max=Math.max(1,...rows.map(x=>x.value));return`<div class="modern-ranked-list">${rows.slice(0,5).map(x=>`<div class="modern-ranked-row"><span>${esc(x.label)}</span><b>${money(x.value)}</b><div><i style="width:${Math.max(3,x.value/max*100)}%"></i></div></div>`).join('')||'<p class="modern-widget-meta">Aucune donnée sur cette période.</p>'}</div>`;}
 function renderWidget(key,state,m,n,range){if(key==='revenue')return`<div class="modern-widget-value">${money(m.revenue)}</div><div class="modern-widget-meta">Hors taxes · période sélectionnée</div>`;if(key==='previous')return`<div class="modern-widget-value">${money(n.revenue)}</div><div class="modern-widget-meta">Période précédente comparable</div>`;if(key==='evolution'){const value=n.revenue?((m.revenue-n.revenue)/Math.abs(n.revenue))*100:null;return`<div class="modern-widget-value ${value>=0?'positive':'negative'}">${value===null?'—':`${value>=0?'+':''}${value.toFixed(1)} %`}</div><div class="modern-widget-meta">Évolution du chiffre d’affaires HT</div>`;}if(key==='revenueTtc')return`<div class="modern-widget-value">${money(m.ttc)}</div><div class="modern-widget-meta">Toutes taxes comprises</div>`;if(key==='collected')return`<div class="modern-widget-value">${money(m.payments)}</div><div class="modern-widget-meta">Paiements confirmés sur la période</div>`;if(key==='outstanding')return`<div class="modern-widget-value">${money(m.outstanding)}</div><div class="modern-widget-meta">Solde de toutes les factures actives</div>`;if(key==='overdue')return`<div class="modern-widget-value ${m.overdue?'negative':''}">${money(m.overdue)}</div><div class="modern-widget-meta">Factures dont l’échéance est dépassée</div>`;if(key==='quotesPending')return`<div class="modern-widget-value">${money(m.pending.reduce((s,x)=>s+Number(x.total_excl_tax),0))}</div><div class="modern-widget-meta">${m.pending.length} devis à suivre</div>`;if(key==='conversion')return`<div class="modern-widget-value">${m.quotes.length?(m.accepted.length/m.quotes.length*100).toFixed(1):'—'}${m.quotes.length?' %':''}</div><div class="modern-widget-meta">${m.accepted.length} accepté(s) sur ${m.quotes.length}</div>`;if(key==='margin')return`<div class="modern-widget-value">${money(m.margin)}</div><div class="modern-widget-meta">${m.revenue?`${(m.margin/m.revenue*100).toFixed(1)} % de taux de marque`:'Aucun revenu facturé'}</div>`;if(key==='pipeline')return`<div class="modern-widget-value">${money(m.pipeline)}</div><div class="modern-widget-meta">${m.opportunities.length} opportunité(s) ouverte(s), valeur pondérée</div>`;if(key==='todayReminders')return`<div class="modern-widget-value">${m.reminders.length}</div><div class="modern-widget-meta">Relances planifiées aujourd’hui</div>`;if(key==='monthly'){const months=Array.from({length:12},(_,index)=>{const start=new Date(new Date().getFullYear(),index,1),end=new Date(new Date().getFullYear(),index+1,1),value=dashboardMetrics(state,{start,end}).revenue;return{label:new Intl.DateTimeFormat('fr-FR',{month:'short'}).format(start).slice(0,3),value};}),max=Math.max(1,...months.map(x=>Math.abs(x.value)));return`<div class="modern-bars">${months.map(x=>`<div class="modern-bar" title="${esc(x.label)} : ${esc(money(x.value))}"><i style="--bar:${Math.max(2,Math.abs(x.value)/max*100)}%"></i><span>${esc(x.label)}</span></div>`).join('')}</div>`;}if(key==='topClients'){const map=new Map();(state.data.documents||[]).filter(x=>['invoice','deposit_invoice','balance_invoice','credit_note'].includes(x.document_type)&&inRange(x.issue_date,range)).forEach(x=>map.set(x.client_id,(map.get(x.client_id)||0)+invoiceSign(x)*Number(x.total_excl_tax)));return ranked([...map].map(([id,value])=>({label:clientName(clientFor(state,id)),value})).sort((a,b)=>b.value-a.value));}if(key==='topItems'){const docIds=new Set((state.data.documents||[]).filter(x=>['invoice','deposit_invoice','balance_invoice'].includes(x.document_type)&&inRange(x.issue_date,range)).map(x=>x.id)),map=new Map();(state.data.lines||[]).filter(x=>docIds.has(x.document_id)&&['item','free_item'].includes(x.line_type)).forEach(x=>map.set(x.name||x.reference||'Sans nom',(map.get(x.name||x.reference||'Sans nom')||0)+Number(x.total_excl_tax)));return ranked([...map].map(([label,value])=>({label,value})).sort((a,b)=>b.value-a.value));}if(key==='recent'){const rows=[...(state.data.activities||[]).map(x=>({date:x.created_at,label:x.subject,type:'Activité'})),...(state.data.documents||[]).map(x=>({date:x.updated_at,label:x.number||x.subject||typeLabels[x.document_type],type:typeLabels[x.document_type]||'Document'}))].sort((a,b)=>String(b.date).localeCompare(String(a.date))).slice(0,6);return`<div class="modern-ranked-list">${rows.map(x=>`<div><b>${esc(x.label)}</b><span class="modern-widget-meta">${esc(x.type)} · ${datetime(x.date)}</span></div>`).join('')||'<p class="modern-widget-meta">Aucune activité récente.</p>'}</div>`;}if(key==='stockAlerts'){const rows=(state.data.levels||[]).filter(level=>{const item=(state.data.catalog||[]).find(x=>x.id===level.item_id);return item&&Number(level.available_quantity)<Number(item.reorder_point||item.minimum_stock||0);}).slice(0,6);return`<div class="modern-ranked-list">${rows.map(level=>{const item=(state.data.catalog||[]).find(x=>x.id===level.item_id);return`<div class="modern-ranked-row"><span>${esc(item?.name||'Article')}</span><b>${Number(level.available_quantity)||0} ${esc(item?.unit||'')}</b></div>`;}).join('')||'<p class="modern-widget-meta">Aucun article sous le seuil.</p>'}</div>`;}return'';}
 function renderDashboard(state){const range=periodRange(ui.dashboard.period),previous=periodRange(ui.dashboard.period,true),m=dashboardMetrics(state,range),n=dashboardMetrics(state,previous),keys=dashboardWidgetKeys(state),periodOptions=[['month','Ce mois'],['previous_month','Mois précédent'],['quarter','Trimestre'],['year','Année'],['previous_year','Année précédente'],['custom','Personnalisé']];document.getElementById('main').innerHTML=header('Tableau de bord','Indicateurs calculés exclusivement depuis les données de votre entreprise.',button(ui.dashboard.configOpen?'Fermer la personnalisation':'Personnaliser','PilozModern.toggleWidgetConfig()')+button('Actualiser','PilozApp.refresh()','btn-p'))+`<div class="modern-toolbar"><label>Période <select onchange="PilozModern.setDashboardPeriod(this.value)">${periodOptions.map(([value,label])=>`<option value="${value}" ${ui.dashboard.period===value?'selected':''}>${label}</option>`).join('')}</select></label>${ui.dashboard.period==='custom'?`<input type="date" aria-label="Début" value="${ui.dashboard.customFrom}" onchange="PilozModern.setDashboardCustom('customFrom',this.value)"><input type="date" aria-label="Fin" value="${ui.dashboard.customTo}" onchange="PilozModern.setDashboardCustom('customTo',this.value)">`:''}</div>${ui.dashboard.configOpen?`<section class="modern-card" style="padding:14px;margin-bottom:14px"><h2 style="font-size:.9rem;margin-bottom:9px">Widgets affichés</h2><div class="phase1-checks">${Object.entries(widgetCatalog).map(([key,def])=>`<label class="phase1-check"><input type="checkbox" ${keys.includes(key)?'checked':''} onchange="PilozModern.toggleWidget('${key}')"><span>${esc(def.title)}</span></label>`).join('')}</div></section>`:''}<div class="modern-dashboard-grid">${keys.map((key,index)=>widgetFrame(key,renderWidget(key,state,m,n,range),index,keys.length)).join('')}</div>`;}

 function documentTypes(kind){return kind==='quote'?['quote']:['invoice','deposit_invoice','balance_invoice','credit_note','proforma_invoice','recurring_invoice'];}
 function documentViews(kind){return kind==='quote'?[['all','Tous'],['draft','Brouillons'],['to_send','À envoyer'],['sent','Envoyés'],['viewed','Consultés'],['pending','En attente'],['accepted','Acceptés'],['rejected','Refusés'],['expired','Expirés'],['invoiced','Facturés'],['archived','Archivés']]:[['all','Toutes'],['draft','Brouillons'],['to_send','À envoyer'],['sent','Envoyées'],['partially_paid','Partiellement payées'],['paid','Payées'],['overdue','En retard'],['deposit_invoice','Acomptes'],['credit_note','Avoirs'],['proforma_invoice','Pro forma']];}
 function documentColumns(kind){return storage.get('piloz_columns_'+kind,defaultColumns[kind]).filter(key=>columnLabels[key]!==undefined);}
 function setDocumentFilter(field,value){ui.document[field]=value;ui.document.page=1;app().render();}
 function setDocumentView(value){ui.document.view=value;ui.document.page=1;app().render();}
 function sortDocuments(key){if(ui.document.sort===key)ui.document.direction=ui.document.direction==='asc'?'desc':'asc';else{ui.document.sort=key;ui.document.direction='asc';}app().render();}
 function effectiveDocumentStatus(row,state){const today=iso(new Date()),status=String(row.status||'draft');if(row.document_type==='quote'&&row.validity_date&&row.validity_date<today&&['to_send','sent','viewed'].includes(status))return'expired';if(['invoice','deposit_invoice','balance_invoice'].includes(row.document_type)&&row.due_date&&row.due_date<today&&Math.max(0,Number(row.total_incl_tax)-paidFor(state,row.id))>0&&!['draft','paid','cancelled','archived'].includes(status))return'overdue';return status;}
 function documentRows(state,kind){const filter=ui.document;let rows=(state.data.documents||[]).filter(x=>documentTypes(kind).includes(x.document_type));if(filter.view!=='all'){if(filter.view==='pending')rows=rows.filter(x=>['to_send','sent','viewed','draft'].includes(effectiveDocumentStatus(x,state)));else if(documentTypes(kind).includes(filter.view))rows=rows.filter(x=>x.document_type===filter.view);else rows=rows.filter(x=>effectiveDocumentStatus(x,state)===filter.view);}const query=filter.search.trim().toLocaleLowerCase('fr');if(query)rows=rows.filter(x=>[x.number,x.subject,clientName(clientFor(state,x.client_id))].some(value=>String(value||'').toLocaleLowerCase('fr').includes(query)));if(filter.client)rows=rows.filter(x=>x.client_id===filter.client);if(filter.owner)rows=rows.filter(x=>x.assigned_user_id===filter.owner);if(filter.opportunity)rows=rows.filter(x=>x.opportunity_id===filter.opportunity);if(filter.dateFrom)rows=rows.filter(x=>x.issue_date>=filter.dateFrom);if(filter.dateTo)rows=rows.filter(x=>x.issue_date<=filter.dateTo);if(filter.min!=='')rows=rows.filter(x=>Number(x.total_excl_tax)>=Number(filter.min));if(filter.max!=='')rows=rows.filter(x=>Number(x.total_excl_tax)<=Number(filter.max));const getter=(row,key)=>key==='client'?clientName(clientFor(state,row.client_id)):key==='margin'?Number(row.total_excl_tax)-costFor(row):key==='cost'?costFor(row):key==='paid'?paidFor(state,row.id):key==='remaining'?Number(row.total_incl_tax)-paidFor(state,row.id):key==='ht'?Number(row.total_excl_tax):key==='vat'?Number(row.total_tax):key==='ttc'?Number(row.total_incl_tax):key==='status'?effectiveDocumentStatus(row,state):row[key];rows.sort((a,b)=>{const av=getter(a,filter.sort),bv=getter(b,filter.sort);return(String(av??'').localeCompare(String(bv??''),'fr',{numeric:true})||(a.id||'').localeCompare(b.id||''))*(filter.direction==='asc'?1:-1);});return rows;}
 function documentCell(key,row,state){const client=clientFor(state,row.client_id),opportunity=opportunityFor(state,row.opportunity_id),paid=paidFor(state,row.id),remaining=Math.max(0,Number(row.total_incl_tax)-paid),margin=Number(row.total_excl_tax)-costFor(row);if(key==='select')return`<td data-label="Sélection"><input type="checkbox" aria-label="Sélectionner" ${ui.document.selected.has(row.id)?'checked':''} onclick="event.stopPropagation();PilozModern.toggleDocumentSelection('${row.id}',this.checked)"></td>`;if(key==='number')return`<td class="primary" data-label="Numéro">${esc(row.number||'Brouillon')}<small>v${Number(row.version)||1}</small></td>`;if(key==='type')return`<td data-label="Type">${esc(typeLabels[row.document_type]||row.document_type)}</td>`;if(key==='client')return`<td class="wrap" data-label="Client">${esc(clientName(client))}<small>${esc(client?.email||'')}</small></td>`;if(key==='subject')return`<td class="wrap" data-label="Objet">${esc(row.subject||'—')}</td>`;if(['issue_date','validity_date','due_date','created_at','last_reminder'].includes(key))return`<td data-label="${esc(columnLabels[key])}">${date(key==='last_reminder'?row.last_reminder_at:row[key])}</td>`;if(key==='ht')return`<td class="money" data-label="HT">${money(row.total_excl_tax,row.currency)}</td>`;if(key==='vat')return`<td class="money" data-label="TVA">${money(row.total_tax,row.currency)}</td>`;if(key==='ttc')return`<td class="money primary" data-label="TTC">${money(row.total_incl_tax,row.currency)}</td>`;if(key==='cost')return`<td class="money erp-cost" data-label="Coût">${money(costFor(row),row.currency)}</td>`;if(key==='margin')return`<td class="money erp-margin" data-label="Marge">${money(margin,row.currency)}<small>${Number(row.total_excl_tax)?(margin/Number(row.total_excl_tax)*100).toFixed(1)+' %':'—'}</small></td>`;if(key==='paid')return`<td class="money" data-label="Encaissé">${money(paid,row.currency)}</td>`;if(key==='remaining')return`<td class="money" data-label="Reste">${money(remaining,row.currency)}</td>`;if(key==='status')return`<td data-label="Statut">${statusBadge(effectiveDocumentStatus(row,state))}</td>`;if(key==='opportunity')return`<td data-label="Opportunité">${esc(opportunity?.name||'—')}</td>`;if(key==='owner')return`<td data-label="Responsable">${row.assigned_user_id===global.PilozRuntime.session.user_id?'Moi':esc(row.assigned_user_id?.slice(0,8)||'—')}</td>`;if(key==='actions')return`<td data-label="Actions"><details class="erp-action-menu" onclick="event.stopPropagation()"><summary class="ic">⋮</summary><div>${button('Ouvrir',`PilozModern.documentAction('${row.id}','open')`,'btn-ghost')}${button('Dupliquer',`PilozModern.documentAction('${row.id}','duplicate')`,'btn-ghost')}${button('Aperçu / PDF',`PilozModern.documentAction('${row.id}','preview')`,'btn-ghost')}${button('Envoyer par e-mail',`PilozModern.documentAction('${row.id}','email')`,'btn-ghost')}${row.document_type==='quote'?button('Convertir en facture',`PilozModern.documentAction('${row.id}','convert')`,'btn-ghost'):''}${button('Archiver',`PilozModern.archiveDocument('${row.id}')`,'btn-ghost')}</div></details></td>`;return'<td>—</td>';}
 function toggleColumns(){ui.document.columnsOpen=!ui.document.columnsOpen;app().render();}
 function setColumn(key,visible){let columns=documentColumns(ui.document.kind);if(visible&&!columns.includes(key))columns.splice(columns.length-1,0,key);if(!visible&&!['select','number','actions'].includes(key))columns=columns.filter(x=>x!==key);storage.set('piloz_columns_'+ui.document.kind,columns);app().render();}
